#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Detections;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Auras;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.stoneEye)]
    public class StoneEye : AIEntityBehaviour
    {
        public StoneEye(string nsp, string name) : base(nsp, name)
        {
            AddAura(new Aura());
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            entity.SetModelProperty("Active", !entity.IsAIFrozen());
            entity.SetAnimationFloat("RayRange", GetRealRange(entity));
        }
        public static float GetRealRange(Entity entity)
        {
            return entity.GetRange() + 40 - RANGE_OFFSET;
        }
        public const float RANGE_OFFSET = 20f;
        public static readonly Vector3 rayOffset = new Vector3(RANGE_OFFSET, 24, 0);

        public class Aura : AuraEffectDefinition
        {
            public Aura() : base(VanillaBuffID.Entity.stoneEyeSlowing, 2)
            {
            }

            public override void GetAuraTargets(AuraEffect auraEffect, List<IBuffTarget> results)
            {
                var entity = auraEffect.Source.GetEntity();
                if (entity == null)
                    return;
                if (entity.IsAIFrozen())
                    return;
                var facingX = entity.GetFacingX();
                detectorBuffer.Clear();
                rayDetector.DetectEntities(entity, detectorBuffer);
                results.AddRange(detectorBuffer);
            }
            public static Detector rayDetector = new StoneEyeDetector(rayOffset)
            {
                canDetectInvisible = true
            };
            public List<Entity> detectorBuffer = new List<Entity>();
        }
    }
}
